-- Acts 21 — To Jerusalem Bound: Paul's Readiness for the Chains
-- Theme: The Spirit-led Servant Walks into Foretold Affliction

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 21,
  'Acts 21 traces Paul''s last free journey — from Miletus along the Asian and Phoenician coasts to Jerusalem, and from the bosom of the church into Roman chains. The voyage names seven ports in rapid succession (Coos, Rhodes, Patara, Tyre, Ptolemais, Caesarea), each a waypoint of hospitality and Spirit-given warning: disciples at Tyre urge Paul through the Spirit not to go up; at Caesarea the prophet Agabus binds himself with Paul''s belt and foretells his imprisonment; Paul answers that he is "ready not to be bound only, but also to die at Jerusalem for the name of the Lord Jesus." Arrived in Jerusalem, Paul reports the Gentile harvest to James and the elders; to appease Jewish believers they urge him to join four men under a vow and pay their expenses. During the seven days of purification, Asian Jews spot him in the temple, accuse him of bringing Gentiles past the soreg, and raise a lynch-mob. The chief captain of the Antonia cohort, Claudius Lysias, rushes down with soldiers and rescues Paul, binding him with two chains. Mistaken for an Egyptian insurrectionist, Paul identifies himself as a Tarsian Jew, obtains leave to speak, and addresses the mob from the fortress stairs in Aramaic.',
  'The Spirit-led Servant Walks into Foretold Affliction',
  'ἑτοίμως',
  'readily, prepared (hetoimōs) — Paul''s settled readiness in v.13 to be bound and to die at Jerusalem for the name of the Lord Jesus.',
  '[{"range":"vv.1-6","title":"Miletus to Tyre — The Disciples'' Warning Through the Spirit"},{"range":"vv.7-9","title":"Ptolemais and Caesarea — Philip the Evangelist and His Four Prophesying Daughters"},{"range":"vv.10-14","title":"Agabus'' Sign-Prophecy and Paul''s Ready Answer"},{"range":"vv.15-16","title":"Up to Jerusalem with Mnason the Cyprian"},{"range":"vv.17-26","title":"James'' Counsel: The Vow and the Four Men"},{"range":"vv.27-30","title":"The Temple Riot — Trophimus and the Asian Jews"},{"range":"vv.31-36","title":"Claudius Lysias and the Antonia Cohort Rescue Paul"},{"range":"vv.37-40","title":"Not the Egyptian — Paul Gains Leave to Address the Mob"}]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And it came to pass, that after we were gotten from them, and had launched, we came with a straight course unto Coos, and the day following unto Rhodes, and from thence unto Patara:',
      'Ὡς δὲ ἐγένετο ἀναχθῆναι ἡμᾶς ἀποσπασθέντας ἀπ᾽ αὐτῶν, εὐθυδρομήσαντες ἤλθομεν εἰς τὴν Κῶν, τῇ δὲ ἑξῆς εἰς τὴν Ῥόδον, κἀκεῖθεν εἰς Πάταρα.',
      'Hōs de egeneto anachthēnai hēmas apospasthentas ap autōn, euthydromēsantes ēlthomen eis tēn Kōn, tē de hexēs eis tēn Rhodon, kakeithen eis Patara.',
      'Apospasthentas ("torn away") is intensive — the farewell at Miletus was a wrenching. Coos (Kos), Rhodes, and Patara are the great Dorian islands and Lycian port; "straight course" (euthydromēsantes) means a direct run before favourable wind.',
      'Even pleasant winds can carry a servant toward chains. Providence''s smooth seas are not always the sign of an easy road ahead.'),
  (2, 'And finding a ship sailing over unto Phenicia, we went aboard, and set forth.',
      'καὶ εὑρόντες πλοῖον διαπερῶν εἰς Φοινίκην, ἐπιβάντες ἀνήχθημεν.',
      'kai heurontes ploion diaperōn eis Phoinikēn, epibantes anēchthēmen.',
      'At Patara they switch from a small coaster to a larger Phoenician cargo vessel running the 400-mile open-sea crossing south of Cyprus straight to Tyre.',
      'God prepares the right ship in the right port at the right hour. His providences link even shipping schedules to apostolic purposes.'),
  (3, 'Now when we had discovered Cyprus, we left it on the left hand, and sailed into Syria, and landed at Tyre: for there the ship was to unlade her burden.',
      'ἀναφάναντες δὲ τὴν Κύπρον, καὶ καταλιπόντες αὐτὴν εὐώνυμον, ἐπλέομεν εἰς Συρίαν, καὶ κατήχθημεν εἰς Τύρον· ἐκεῖσε γὰρ ἦν τὸ πλοῖον ἀποφορτιζόμενον τὸν γόμον.',
      'anaphanantes de tēn Kypron, kai katalipontes autēn euōnymon, epleomen eis Syrian, kai katēchthēmen eis Tyron; ekeise gar ēn to ploion apophortizomenon ton gomon.',
      'Anaphanantes is a nautical technical term — "having sighted/raised land." Tyre was a Phoenician commercial hub; the week''s layover for unloading cargo providentially gives Paul time with disciples there.',
      'Even commercial cargo-runs are laid under contribution to the gospel. God''s apostles ride trade winds for the kingdom.'),
  (4, 'And finding disciples, we tarried there seven days: who said to Paul through the Spirit, that he should not go up to Jerusalem.',
      'καὶ ἀνευρόντες μαθητὰς ἐπεμείναμεν αὐτοῦ ἡμέρας ἑπτά· οἵτινες τῷ Παύλῳ ἔλεγον διὰ τοῦ Πνεύματος, μὴ ἀναβαίνειν εἰς Ἱερουσαλήμ.',
      'kai aneurontes mathētas epemeinamen autou hēmeras hepta; hoitines tō Paulō elegon dia tou Pneumatos, mē anabainein eis Ierousalēm.',
      'The Tyrian church, likely planted by those scattered after Stephen''s martyrdom (11:19), foresees Paul''s sufferings "through the Spirit" and draws a loving but mistaken inference — urging him to avoid Jerusalem. The Spirit reveals coming bonds (20:23); love interprets the revelation as a prohibition.',
      'The Spirit''s prophetic warning and the saints'' pastoral application are not always identical. Revelation discloses fact; wisdom must weigh implications under the Lord''s primary call.'),
  (5, 'And when we had accomplished those days, we departed and went our way; and they all brought us on our way, with wives and children, till we were out of the city: and we kneeled down on the shore, and prayed.',
      'ὅτε δὲ ἐγένετο ἡμᾶς ἐξαρτίσαι τὰς ἡμέρας, ἐξελθόντες ἐπορευόμεθα, προπεμπόντων ἡμᾶς πάντων σὺν γυναιξὶ καὶ τέκνοις ἕως ἔξω τῆς πόλεως· καὶ θέντες τὰ γόνατα ἐπὶ τὸν αἰγιαλὸν προσηυξάμεθα.',
      'hote de egeneto hēmas exartisai tas hēmeras, exelthontes eporeuometha, propempontōn hēmas pantōn syn gynaixi kai teknois heōs exō tēs poleōs; kai thentes ta gonata epi ton aigialon prosēuxametha.',
      'Whole families — wives and children — accompany the apostle to the shore. A congregational prayer meeting on the sand, knees in the sand, is the parting benediction.',
      'Gospel hospitality embraces families, not bachelors only. Christian partings kneel to pray, for the God who parts His servants is also the God who keeps them.'),
  (6, 'And when we had taken our leave one of another, we took ship; and they returned home again.',
      'καὶ ἀσπασάμενοι ἀλλήλους, ἐπέβημεν εἰς τὸ πλοῖον, ἐκεῖνοι δὲ ὑπέστρεψαν εἰς τὰ ἴδια.',
      'kai aspasamenoi allēlous, epebēmen eis to ploion, ekeinoi de hypestrepsan eis ta idia.',
      '"Returned home" (eis ta idia) — the same phrase used of the beloved disciple taking Mary home in John 19:27. Ordinary life resumes; the drama of mission moves on.',
      'Saints say goodbye and return to their own houses, but the bond of the Spirit crosses sea and distance. One in Christ, though scattered in body.'),
  (7, 'And when we had finished our course from Tyre, we came to Ptolemais, and saluted the brethren, and abode with them one day.',
      'Ἡμεῖς δὲ τὸν πλοῦν διανύσαντες ἀπὸ Τύρου κατηντήσαμεν εἰς Πτολεμαΐδα, καὶ ἀσπασάμενοι τοὺς ἀδελφοὺς ἐμείναμεν ἡμέραν μίαν παρ᾽ αὐτοῖς.',
      'Hēmeis de ton ploun dianysantes apo Tyrou katēntēsamen eis Ptolemaida, kai aspasamenoi tous adelphous emeinamen hēmeran mian par autois.',
      'Ptolemais (OT Accho; modern Acre) is 27 miles south of Tyre. The existence of "brethren" in every coastal town shows how widely the gospel had already spread along the Phoenician shore.',
      'The gospel plants pockets of believers in every harbour. Wherever the apostles travel, they find already-planted saints to greet.'),
  (8, 'And the next day we that were of Paul''s company departed, and came unto Caesarea: and we entered into the house of Philip the evangelist, which was one of the seven; and abode with him.',
      'τῇ δὲ ἐπαύριον ἐξελθόντες οἱ περὶ τὸν Παῦλον ἤλθομεν εἰς Καισάρειαν· καὶ εἰσελθόντες εἰς τὸν οἶκον Φιλίππου τοῦ εὐαγγελιστοῦ, ὄντος ἐκ τῶν ἑπτά, ἐμείναμεν παρ᾽ αὐτῷ.',
      'tē de epaurion exelthontes hoi peri ton Paulon ēlthomen eis Kaisareian; kai eiselthontes eis ton oikon Philippou tou euangelistou, ontos ek tōn hepta, emeinamen par autō.',
      'Caesarea Maritima — Herod''s harbour city, Roman administrative capital of Judaea. Philip is the Philip of Acts 6:5; 8:5-40, now settled in Caesarea for some 20 years. Paul, who once hunted the scattered deacon''s converts, is now his houseguest — a living parable of reconciliation.',
      'The gospel heals what persecution sundered. The former persecutor and the scattered deacon dine together under one roof to the glory of Christ.'),
  (9, 'And the same man had four daughters, virgins, which did prophesy.',
      'τούτῳ δὲ ἦσαν θυγατέρες παρθένοι τέσσαρες προφητεύουσαι.',
      'toutō de ēsan thygateres parthenoi tessares prophēteuousai.',
      'Four prophesying daughters (cf. Joel 2:28 fulfilled). Their virginity is noted because unmarried women had a recognized status in the apostolic church (1 Cor 7:34). Prophesying women were active but under the order of 1 Cor 11:5.',
      'The Spirit''s gifts fall on sons and daughters alike (Joel 2, Acts 2:17). The household of a faithful evangelist becomes a household of gifted ministry.'),
  (10, 'And as we tarried there many days, there came down from Judaea a certain prophet, named Agabus.',
      'ἐπιμενόντων δὲ ἡμῶν ἡμέρας πλείους, κατῆλθέν τις ἀπὸ τῆς Ἰουδαίας προφήτης ὀνόματι Ἄγαβος.',
      'epimenontōn de hēmōn hēmeras pleious, katēlthen tis apo tēs Ioudaias prophētēs onomati Agabos.',
      'Agabus is the same prophet of Acts 11:28 who foretold the Claudian famine. A trustworthy prophetic voice over long years — verified once already.',
      'The Spirit provides multi-generational prophetic voices. A prophet''s past accuracy commends his present message.'),
  (11, 'And when he was come unto us, he took Paul''s girdle, and bound his own hands and feet, and said, Thus saith the Holy Ghost, So shall the Jews at Jerusalem bind the man that owneth this girdle, and shall deliver him into the hands of the Gentiles.',
      'καὶ ἐλθὼν πρὸς ἡμᾶς, καὶ ἄρας τὴν ζώνην τοῦ Παύλου, δήσας τε αὐτοῦ τὰς χεῖρας καὶ τοὺς πόδας εἶπε, Τάδε λέγει τὸ Πνεῦμα τὸ Ἅγιον, Τὸν ἄνδρα οὗ ἐστιν ἡ ζώνη αὕτη, οὕτω δήσουσιν ἐν Ἱερουσαλὴμ οἱ Ἰουδαῖοι, καὶ παραδώσουσιν εἰς χεῖρας ἐθνῶν.',
      'kai elthōn pros hēmas, kai aras tēn zōnēn tou Paulou, dēsas te autou tas cheiras kai tous podas eipe, Tade legei to Pneuma to Hagion, Ton andra hou estin hē zōnē hautē, houtō dēsousin en Ierousalēm hoi Ioudaioi, kai paradōsousin eis cheiras ethnōn.',
      'Sign-prophecy in the OT manner — Ahijah tore a garment (1 Kgs 11:29-31); Jeremiah broke a potter''s flask (Jer 19). "Tade legei" — "Thus saith" — is the exact Septuagint formula of OT prophetic oracles. The "Gentiles" (ethnē) means the Romans, into whose hands Paul will indeed be delivered (vv.33ff).',
      'God''s prophets still speak with the authority of "Thus saith the Lord." The acted sign drives the word home to eye as well as ear.'),
  (12, 'And when we heard these things, both we, and they of that place, besought him not to go up to Jerusalem.',
      'ὡς δὲ ἠκούσαμεν ταῦτα, παρεκαλοῦμεν ἡμεῖς τε καὶ οἱ ἐντόπιοι, τοῦ μὴ ἀναβαίνειν αὐτὸν εἰς Ἱερουσαλήμ.',
      'hōs de ēkousamen tauta, parekaloumen hēmeis te kai hoi entopioi, tou mē anabainein auton eis Ierousalēm.',
      '"We" includes Luke himself. Love in both visitors and locals unite in pleading. The plea is human — the foretelling is divine; love takes the foretelling as a warning to flee.',
      'Love does not always read God''s warnings correctly. Genuine affection can still resist the very sufferings God has appointed His servant to bear.'),
  (13, 'Then Paul answered, What mean ye to weep and to break mine heart? for I am ready not to be bound only, but also to die at Jerusalem for the name of the Lord Jesus.',
      'ἀπεκρίθη δὲ ὁ Παῦλος, Τί ποιεῖτε κλαίοντες καὶ συνθρύπτοντές μου τὴν καρδίαν; ἐγὼ γὰρ οὐ μόνον δεθῆναι, ἀλλὰ καὶ ἀποθανεῖν εἰς Ἱερουσαλὴμ ἑτοίμως ἔχω, ὑπὲρ τοῦ ὀνόματος τοῦ Κυρίου Ἰησοῦ.',
      'apekrithē de ho Paulos, Ti poieite klaiontes kai synthryptontes mou tēn kardian? egō gar ou monon dethēnai, alla kai apothanein eis Ierousalēm hetoimōs echō, hyper tou onomatos tou Kyriou Iēsou.',
      'Synthryptontes ("crushing together") — the only NT use of this verb. Their tears break his heart; they do not bend his resolve. "For the name of the Lord Jesus" is the Martyr''s creed (cf. 9:16).',
      'True readiness does not need to feel no pain — it feels it fully and still presses on. The servant weighs his heart''s breaking against his Master''s honour and chooses the Lord.'),
  (14, 'And when he would not be persuaded, we ceased, saying, The will of the Lord be done.',
      'μὴ πειθομένου δὲ αὐτοῦ, ἡσυχάσαμεν εἰπόντες, Τὸ θέλημα τοῦ Κυρίου γενέσθω.',
      'mē peithomenou de autou, hēsychasamen eipontes, To thelēma tou Kyriou genesthō.',
      'The same Gethsemane prayer Jesus taught (Matt 6:10; 26:42). Silence after submission — they stop weeping aloud, for the matter is with God.',
      'Where faith cannot alter the purpose, submission learns to pray it. "Thy will be done" is not resignation but adoration.'),
  (15, 'And after those days we took up our carriages, and went up to Jerusalem.',
      'Μετὰ δὲ τὰς ἡμέρας ταύτας ἀποσκευασάμενοι ἀνεβαίνομεν εἰς Ἱερουσαλήμ.',
      'Meta de tas hēmeras tautas aposkeuasamenoi anebainomen eis Ierousalēm.',
      '"Carriages" (KJV) = baggage, not vehicles. The 65-mile ascent from Caesarea climbs some 2500 feet.',
      'The ordinary packing up of luggage becomes the first step of martyrdom. God uses daily preparations as the road to His appointments.'),
  (16, 'There went with us also certain of the disciples of Caesarea, and brought with them one Mnason of Cyprus, an old disciple, with whom we should lodge.',
      'συνῆλθον δὲ καὶ τῶν μαθητῶν ἀπὸ Καισαρείας σὺν ἡμῖν, ἄγοντες παρ᾽ ᾧ ξενισθῶμεν, Μνάσωνί τινι Κυπρίῳ, ἀρχαίῳ μαθητῇ.',
      'synēlthon de kai tōn mathētōn apo Kaisareias syn hēmin, agontes par hō xenisthōmen, Mnasōni tini Kypriō, archaiō mathētē.',
      'Mnason is Hellenistic Jewish — a Cypriot, like Barnabas. "Old disciple" (archaios mathētēs) means early — possibly converted at Pentecost or in Jesus'' own ministry.',
      'The long-standing believers are the unsung scaffolding of gospel missions. First-generation disciples open their doors for the apostles who follow.'),
  (17, 'And when we were come to Jerusalem, the brethren received us gladly.',
      'Γενομένων δὲ ἡμῶν εἰς Ἱεροσόλυμα, ἀσμένως ἐδέξαντο ἡμᾶς οἱ ἀδελφοί.',
      'Genomenōn de hēmōn eis Ierosolyma, asmenōs edexanto hēmas hoi adelphoi.',
      '"Gladly" (asmenōs) — the Gentile collection (Rom 15:25-27) has arrived; the Jerusalem brethren rejoice.',
      'The Gentile offering for Jewish saints is a visible embrace — and it is received gladly. The gospel makes one body of ancient and young in the faith.'),
  (18, 'And the day following Paul went in with us unto James; and all the elders were present.',
      'τῇ δὲ ἐπιούσῃ εἰσῄει ὁ Παῦλος σὺν ἡμῖν πρὸς Ἰάκωβον, πάντες τε παρεγένοντο οἱ πρεσβύτεροι.',
      'tē de epiousē eisēei ho Paulos syn hēmin pros Iakōbon, pantes te paregenonto hoi presbyteroi.',
      'James, the Lord''s brother, is now sole head of the Jerusalem eldership (cf. 12:17; 15:13; Gal 1:19; 2:9). Luke''s "we" includes himself at this historic summit.',
      'Ordered eldership, not apostolic charisma alone, governs the mother church. Authority is collegial — Paul meets "all the elders."'),
  (19, 'And when he had saluted them, he declared particularly what things God had wrought among the Gentiles by his ministry.',
      'καὶ ἀσπασάμενος αὐτούς, ἐξηγεῖτο καθ᾽ ἓν ἕκαστον ὧν ἐποίησεν ὁ Θεὸς ἐν τοῖς ἔθνεσι διὰ τῆς διακονίας αὐτοῦ.',
      'kai aspasamenos autous, exēgeito kath hen hekaston hōn epoiēsen ho Theos en tois ethnesi dia tēs diakonias autou.',
      'Exēgeito — the verb behind "exegete," a detailed unfolding. "One by one" (kath hen hekaston) — not a speech, a report. Paul attributes all to God''s doing through his ministry.',
      'The servant reports — God has wrought. Mission reports glorify the Doer, not the doer''s instrument; Paul recounts "what God had done."'),
  (20, 'And when they heard it, they glorified the Lord, and said unto him, Thou seest, brother, how many thousands of Jews there are which believe; and they are all zealous of the law:',
      'οἱ δὲ ἀκούσαντες ἐδόξαζον τὸν Κύριον, εἰπόν τε αὐτῷ, Θεωρεῖς, ἀδελφέ, πόσαι μυριάδες εἰσὶν Ἰουδαίων τῶν πεπιστευκότων· καὶ πάντες ζηλωταὶ τοῦ νόμου ὑπάρχουσι·',
      'hoi de akousantes edoxazon ton Kyrion, eipon te autō, Theōreis, adelphe, posai myriades eisin Ioudaiōn tōn pepisteukotōn; kai pantes zēlōtai tou nomou hyparchousi;',
      'Myriades ("tens of thousands") — literally "many myriads." By AD 57 the Jerusalem church numbered in the tens of thousands, all still keeping Torah with fervour. "Zealous for the law" is cultural observance, not legalistic salvation.',
      'Jewish Christians kept Torah as their ancestral way of life even while resting for salvation on Christ alone. Christianity in the first generation took both Jewish and Gentile forms without dividing the church.'),
  (21, 'And they are informed of thee, that thou teachest all the Jews which are among the Gentiles to forsake Moses, saying that they ought not to circumcise their children, neither to walk after the customs.',
      'κατηχήθησαν δὲ περὶ σοῦ, ὅτι ἀποστασίαν διδάσκεις ἀπὸ Μωϋσέως τοὺς κατὰ τὰ ἔθνη πάντας Ἰουδαίους, λέγων μὴ περιτέμνειν αὐτοὺς τὰ τέκνα, μηδὲ τοῖς ἔθεσι περιπατεῖν.',
      'katēchēthēsan de peri sou, hoti apostasian didaskeis apo Mōyseōs tous kata ta ethnē pantas Ioudaious, legōn mē peritemnein autous ta tekna, mēde tois ethesi peripatein.',
      'Apostasian — "apostasy" — is the loaded word. Paul taught Gentiles they need not be circumcised (Gal 2:3-5), not that Jewish Christians must abandon their ancestral ways. The charge misreports the teaching.',
      'Gospel freedom is repeatedly misreported. Preachers of grace must bear the cost of being misunderstood as antinomians.'),
  (22, 'What is it therefore? the multitude must needs come together: for they will hear that thou art come.',
      'τί οὖν ἐστι; πάντως δεῖ πλῆθος συνελθεῖν· ἀκούσονται γὰρ ὅτι ἐλήλυθας.',
      'ti oun esti; pantōs dei plēthos synelthein; akousontai gar hoti elēlythas.',
      'An assembly of the whole body is inevitable once Paul''s arrival spreads. James and the elders see the need for a public sign of Paul''s Jewish piety.',
      'Rumour cannot be left unanswered. Where public offence has been taken, public assurance is the path of love.'),
  (23, 'Do therefore this that we say to thee: We have four men which have a vow on them;',
      'τοῦτο οὖν ποίησον ὅ σοι λέγομεν· εἰσὶν ἡμῖν ἄνδρες τέσσαρες εὐχὴν ἔχοντες ἐφ᾽ ἑαυτῶν·',
      'touto oun poiēson ho soi legomen; eisin hēmin andres tessares euchēn echontes eph heautōn;',
      'The "vow" (euchē) is the Nazirite vow of Num 6:1-21. Completion required seven days of purification and prescribed offerings at the temple.',
      'Pastoral wisdom proposes visible actions to defuse invisible suspicions. Submitting to customary rites does not compromise grace when done freely for the flock''s peace.'),
  (24, 'Them take, and purify thyself with them, and be at charges with them, that they may shave their heads: and all may know that those things, whereof they were informed concerning thee, are nothing; but that thou thyself also walkest orderly, and keepest the law.',
      'τούτους παραλαβὼν ἁγνίσθητι σὺν αὐτοῖς, καὶ δαπάνησον ἐπ᾽ αὐτοῖς, ἵνα ξυρήσωνται τὴν κεφαλήν, καὶ γνῶσι πάντες ὅτι ὧν κατήχηνται περὶ σοῦ οὐδέν ἐστιν, ἀλλὰ στοιχεῖς καὶ αὐτὸς τὸν νόμον φυλάσσων.',
      'toutous paralabōn hagnisthēti syn autois, kai dapanēson ep autois, hina xyrēsōntai tēn kephalēn, kai gnōsi pantes hoti hōn katēchēntai peri sou ouden estin, alla stoicheis kai autos ton nomon phylassōn.',
      'Paying the Nazirite expenses was a recognized act of Jewish piety (Josephus, Ant. 19.6.1). Shaving the head sealed the vow''s completion.',
      'Paul is willing "to the Jews as a Jew" (1 Cor 9:20) without compromising the gospel. Love accommodates where truth is not at stake.'),
  (25, 'As touching the Gentiles which believe, we have written and concluded that they observe no such thing, save only that they keep themselves from things offered to idols, and from blood, and from strangled, and from fornication.',
      'περὶ δὲ τῶν πεπιστευκότων ἐθνῶν ἡμεῖς ἐπεστείλαμεν, κρίναντες μηδὲν τοιοῦτον τηρεῖν αὐτούς, εἰ μὴ φυλάσσεσθαι αὐτοὺς τό τε εἰδωλόθυτον καὶ τὸ αἷμα καὶ πνικτὸν καὶ πορνείαν.',
      'peri de tōn pepisteukotōn ethnōn hēmeis epesteilamen, krinantes mēden toiouton tērein autous, ei mē phylassesthai autous to te eidōlothyton kai to haima kai pnikton kai porneian.',
      'The Jerusalem Council decree of Acts 15:29 is reaffirmed unchanged. Jewish believers may keep Torah customs; Gentile believers are not under them.',
      'The two-track policy of Acts 15 stands. Unity does not require uniformity of ceremonial practice.'),
  (26, 'Then Paul took the men, and the next day purifying himself with them entered into the temple, to signify the accomplishment of the days of purification, until that an offering should be offered for every one of them.',
      'τότε ὁ Παῦλος παραλαβὼν τοὺς ἄνδρας, τῇ ἐχομένῃ ἡμέρᾳ σὺν αὐτοῖς ἁγνισθεὶς εἰσῄει εἰς τὸ ἱερόν, διαγγέλλων τὴν ἐκπλήρωσιν τῶν ἡμερῶν τοῦ ἁγνισμοῦ, ἕως οὗ προσηνέχθη ὑπὲρ ἑνὸς ἑκάστου αὐτῶν ἡ προσφορά.',
      'tote ho Paulos paralabōn tous andras, tē echomenē hēmera syn autois hagnistheis eisēei eis to hieron, diangellōn tēn ekplērōsin tōn hēmerōn tou hagnismou, heōs hou prosēnechthē hyper henos hekastou autōn hē prosphora.',
      'Paul joins the vow at the Court of the Israelites; he pays the lambs, ram, and grain offerings of Num 6:14-15 for each man.',
      'The apostle of free grace pays for temple sacrifices to preserve fellowship. Grace stoops to cultural forms when love for the flock requires it.'),
  (27, 'And when the seven days were almost ended, the Jews which were of Asia, when they saw him in the temple, stirred up all the people, and laid hands on him,',
      'ὡς δὲ ἔμελλον αἱ ἑπτὰ ἡμέραι συντελεῖσθαι, οἱ ἀπὸ τῆς Ἀσίας Ἰουδαῖοι, θεασάμενοι αὐτὸν ἐν τῷ ἱερῷ, συνέχεον πάντα τὸν ὄχλον, καὶ ἐπέβαλον τὰς χεῖρας ἐπ᾽ αὐτόν,',
      'hōs de emellon hai hepta hēmerai synteleisthai, hoi apo tēs Asias Ioudaioi, theasamenoi auton en tō hierō, synecheon panta ton ochlon, kai epebalon tas cheiras ep auton,',
      '"Asian Jews" (from Ephesus and the province) are Paul''s long-standing opponents (cf. Acts 19:9; 20:19). At Pentecost Jerusalem is packed with pilgrims; the crowd accelerates the riot.',
      'Old enemies often close the last gate. Paul''s Ephesian adversaries find him now in Jerusalem.'),
  (28, 'Crying out, Men of Israel, help: This is the man, that teacheth all men every where against the people, and the law, and this place: and further brought Greeks also into the temple, and hath polluted this holy place.',
      'κράζοντες, Ἄνδρες Ἰσραηλῖται, βοηθεῖτε· οὗτός ἐστιν ὁ ἄνθρωπος, ὁ κατὰ τοῦ λαοῦ καὶ τοῦ νόμου καὶ τοῦ τόπου τούτου πάντας πανταχοῦ διδάσκων· ἔτι τε καὶ Ἕλληνας εἰσήγαγεν εἰς τὸ ἱερόν, καὶ κεκοίνωκε τὸν ἅγιον τόπον τοῦτον.',
      'krazontes, Andres Israēlitai, boētheite; houtos estin ho anthrōpos, ho kata tou laou kai tou nomou kai tou topou toutou pantas pantachou didaskōn; eti te kai Hellēnas eisēgagen eis to hieron, kai kekoinōke ton hagion topon touton.',
      'Three slanders echo those against Jesus (Mark 14:58) and Stephen (Acts 6:13) — against people, law, and temple. The temple had a stone "soreg" barrier warning Gentiles on pain of death; inscriptions from this period have been recovered.',
      'The charge of polluting what is holy has always been flung at those who open it to all nations. The gospel calls every boundary to reconsider itself.'),
  (29, '(For they had seen before with him in the city Trophimus an Ephesian, whom they supposed that Paul had brought into the temple.)',
      'ἦσαν γὰρ προεωρακότες Τρόφιμον τὸν Ἐφέσιον ἐν τῇ πόλει σὺν αὐτῷ, ὃν ἐνόμιζον ὅτι εἰς τὸ ἱερὸν εἰσήγαγεν ὁ Παῦλος.',
      'ēsan gar proeōrakotes Trophimon ton Ephesion en tē polei syn autō, hon enomizon hoti eis to hieron eisēgagen ho Paulos.',
      'Trophimus is among the Gentile delegates from Asia (20:4). Seen with Paul in the city, he is wrongly imagined inside the temple. The whole riot is a supposition.',
      'Slanders often begin as assumptions and harden into lynchings. The innocent pay for what onlookers merely imagined.'),
  (30, 'And all the city was moved, and the people ran together: and they took Paul, and drew him out of the temple: and forthwith the doors were shut.',
      'ἐκινήθη τε ἡ πόλις ὅλη, καὶ ἐγένετο συνδρομὴ τοῦ λαοῦ· καὶ ἐπιλαβόμενοι τοῦ Παύλου εἷλκον αὐτὸν ἔξω τοῦ ἱεροῦ· καὶ εὐθέως ἐκλείσθησαν αἱ θύραι.',
      'ekinēthē te hē polis holē, kai egeneto syndromē tou laou; kai epilabomenoi tou Paulou heilkon auton exō tou hierou; kai eutheōs ekleisthēsan hai thyrai.',
      'Heilkon — "dragged" — implies violent mob action. The Levite gatekeepers slam the doors to prevent bloodshed in the courts (cf. 2 Kgs 11:15).',
      'Even amid frenzied violence God preserves His servant. The slammed temple doors protect the apostle from the mob''s fury.'),
  (31, 'And as they went about to kill him, tidings came unto the chief captain of the band, that all Jerusalem was in an uproar.',
      'ζητούντων δὲ αὐτὸν ἀποκτεῖναι, ἀνέβη φάσις τῷ χιλιάρχῳ τῆς σπείρης, ὅτι ὅλη συγκέχυται Ἱερουσαλήμ·',
      'zētountōn de auton apokteinai, anebē phasis tō chiliarchō tēs speirēs, hoti holē syngkechytai Ierousalēm;',
      'The "chief captain" (chiliarchos) is the Roman military tribune — commander of a cohort (speirē) of 600-1000 men quartered in the Antonia Fortress adjoining the temple''s northwest corner. Named in 23:26 as Claudius Lysias.',
      'Rome, though pagan, becomes God''s instrument of rescue. The providential hand spares the apostle through an imperial officer.'),
  (32, 'Who immediately took soldiers and centurions, and ran down unto them: and when they saw the chief captain and the soldiers, they left beating of Paul.',
      'ὃς ἐξαυτῆς παραλαβὼν στρατιώτας καὶ ἑκατοντάρχους, κατέδραμεν ἐπ᾽ αὐτούς· οἱ δέ, ἰδόντες τὸν χιλίαρχον καὶ τοὺς στρατιώτας, ἐπαύσαντο τύπτοντες τὸν Παῦλον.',
      'hos exautēs paralabōn stratiōtas kai hekatontarchous, katedramen ep autous; hoi de, idontes ton chiliarchon kai tous stratiōtas, epausanto typtontes ton Paulon.',
      'Centurions (plural) commanded 80-100 men each; Lysias brings a substantial force. Stairways descended directly from the Antonia into the outer court.',
      'The sight of lawful authority sobers a mob. The God who calms storms at sea also calms crowds on stone pavements.'),
  (33, 'Then the chief captain came near, and took him, and commanded him to be bound with two chains; and demanded who he was, and what he had done.',
      'ἐγγίσας δὲ ὁ χιλίαρχος ἐπελάβετο αὐτοῦ, καὶ ἐκέλευσε δεθῆναι ἁλύσεσι δυσί· καὶ ἐπυνθάνετο τίς ἂν εἴη, καὶ τί ἐστι πεποιηκώς.',
      'engisas de ho chiliarchos epelabeto autou, kai ekeleuse dethēnai halysesi dysi; kai epynthaneto tis an eiē, kai ti esti pepoiēkōs.',
      '"Two chains" — Agabus''s word literally fulfilled (v.11). Paul is thus already in Roman bonds as Agabus prophesied.',
      'Prophecy is vindicated to the letter. The two chains bind the apostle but release the word from every doubt.'),
  (34, 'And some cried one thing, some another, among the multitude: and when he could not know the certainty for the tumult, he commanded him to be carried into the castle.',
      'ἄλλοι δὲ ἄλλο τι ἐβόων ἐν τῷ ὄχλῳ· μὴ δυνάμενος δὲ γνῶναι τὸ ἀσφαλὲς διὰ τὸν θόρυβον, ἐκέλευσεν ἄγεσθαι αὐτὸν εἰς τὴν παρεμβολήν.',
      'alloi de allo ti eboōn en tō ochlō; mē dynamenos de gnōnai to asphales dia ton thorybon, ekeleusen agesthai auton eis tēn parembolēn.',
      'Parembolēn — military camp, here the Antonia barracks. A crowd ruled by passion cannot be cross-examined; Roman discipline requires the prisoner removed.',
      'Mob wisdom cannot supply a verdict. Only ordered inquiry — not shouting — can deliver truth.'),
  (35, 'And when he came upon the stairs, so it was, that he was borne of the soldiers for the violence of the people.',
      'ὅτε δὲ ἐγένετο ἐπὶ τοὺς ἀναβαθμούς, συνέβη βαστάζεσθαι αὐτὸν ὑπὸ τῶν στρατιωτῶν διὰ τὴν βίαν τοῦ ὄχλου.',
      'hote de egeneto epi tous anabathmous, synebē bastazesthai auton hypo tōn stratiōtōn dia tēn bian tou ochlou.',
      'The stairway between the temple court and the Antonia is still visible archaeologically. "Carried" — the soldiers lift Paul off his feet to save him from the press.',
      'God''s servants are often carried through crisis, literally. When strength fails, other shoulders bear the beloved.'),
  (36, 'For the multitude of the people followed after, crying, Away with him.',
      'ἠκολούθει γὰρ τὸ πλῆθος τοῦ λαοῦ κρᾶζον, Αἶρε αὐτόν.',
      'ēkolouthei gar to plēthos tou laou krazon, Aire auton.',
      'Aire auton — the very cry shouted against Jesus (Luke 23:18; John 19:15). Paul now walks his Master''s path.',
      'The servant is not above his Lord. The same cry that crucified Christ now rises against the apostle for Christ''s sake.'),
  (37, 'And as Paul was to be led into the castle, he said unto the chief captain, May I speak unto thee? Who said, Canst thou speak Greek?',
      'Μέλλων τε εἰσάγεσθαι εἰς τὴν παρεμβολὴν ὁ Παῦλος λέγει τῷ χιλιάρχῳ, Εἰ ἔξεστί μοι εἰπεῖν τι πρός σε; Ὁ δὲ ἔφη, Ἑλληνιστὶ γινώσκεις;',
      'Mellōn te eisagesthai eis tēn parembolēn ho Paulos legei tō chiliarchō, Ei exesti moi eipein ti pros se? Ho de ephē, Hellēnisti ginōskeis?',
      'Paul''s cultured Koine Greek startles Lysias; the tribune had assumed him a rough insurrectionist.',
      'Educated speech opens doors that shouting closes. The apostle moves with grace among every class and tongue.'),
  (38, 'Art not thou that Egyptian, which before these days madest an uproar, and leddest out into the wilderness four thousand men that were murderers?',
      'οὐκ ἄρα σὺ εἶ ὁ Αἰγύπτιος ὁ πρὸ τούτων τῶν ἡμερῶν ἀναστατώσας καὶ ἐξαγαγὼν εἰς τὴν ἔρημον τοὺς τετρακισχιλίους ἄνδρας τῶν σικαρίων;',
      'ouk ara sy ei ho Aigyptios ho pro toutōn tōn hēmerōn anastatōsas kai exagagōn eis tēn erēmon tous tetrakischilious andras tōn sikariōn?',
      'Josephus (Ant. 20.8.6; War 2.13.5) records this Egyptian false-prophet who led 30,000 to the Mount of Olives expecting the walls to fall — crushed by Felix c. AD 54; the leader escaped. "Sikarii" ("dagger-men") were Zealot assassins.',
      'The gospel''s messengers are often mistaken for revolutionary villains. Luke delights to show — from named eyewitnesses — that the charge is false.'),
  (39, 'But Paul said, I am a man which am a Jew of Tarsus, a city in Cilicia, a citizen of no mean city: and, I beseech thee, suffer me to speak unto the people.',
      'εἶπε δὲ ὁ Παῦλος, Ἐγὼ ἄνθρωπος μέν εἰμι Ἰουδαῖος, Ταρσεύς, τῆς Κιλικίας οὐκ ἀσήμου πόλεως πολίτης· δέομαι δέ σου, ἐπίτρεψόν μοι λαλῆσαι πρὸς τὸν λαόν.',
      'eipe de ho Paulos, Egō anthrōpos men eimi Ioudaios, Tarseus, tēs Kilikias ouk asēmou poleōs politēs; deomai de sou, epitrepson moi lalēsai pros ton laon.',
      'Tarsus was a free city, a renowned university town, birthplace of Stoicism''s Zeno. "No mean city" (ouk asēmou) — litotes for "very distinguished." Paul says "Jew" first — his heart-identity.',
      'The apostle owns his Jewish birth and Gentile citizenship without contradiction. Grace does not erase the providential shape of a life.'),
  (40, 'And when he had given me leave, Paul stood on the stairs, and beckoned with the hand unto the people. And when there was made a great silence, he spake unto them in the Hebrew tongue, saying,',
      'ἐπιτρέψαντος δὲ αὐτοῦ, ὁ Παῦλος ἑστὼς ἐπὶ τῶν ἀναβαθμῶν κατέσεισε τῇ χειρὶ τῷ λαῷ. πολλῆς δὲ σιγῆς γενομένης, προσεφώνησε τῇ Ἑβραΐδι διαλέκτῳ, λέγων,',
      'epitrepsantos de autou, ho Paulos hestōs epi tōn anabathmōn kateseise tē cheiri tō laō. pollēs de sigēs genomenēs, prosephōnēse tē Hebraidi dialektō, legōn,',
      '"Hebrew tongue" (Hebraïs dialektos) — here Aramaic, the everyday speech of Judaea. Paul''s gesture and mother-tongue silence the mob. The stairway becomes a pulpit.',
      'God gives His servant an unexpected pulpit — borne in chains, raised above the crowd, granted perfect silence. The gospel finds its platform wherever the King wills.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 21
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἀποσπασθέντας', 'apospasthentas', 'G645', 'Torn away — the wrenching farewell from the Ephesian elders.', 1),
  (1, 'εὐθυδρομήσαντες', 'euthydromēsantes', 'G2113', 'Running a straight course — nautical term for sailing directly with favourable wind.', 2),
  (4, 'ἀνευρόντες', 'aneurontes', 'G429', 'Having sought out and found — deliberate tracking down of disciples.', 3),
  (4, 'διὰ τοῦ Πνεύματος', 'dia tou Pneumatos', 'G1223/G4151', 'Through the Spirit — prophetic foresight of Paul''s coming bonds.', 4),
  (9, 'παρθένοι προφητεύουσαι', 'parthenoi prophēteuousai', 'G3933/G4395', 'Virgins prophesying — Joel 2:28 fulfilled in Philip''s household.', 5),
  (11, 'ζώνην', 'zōnēn', 'G2223', 'Girdle, belt — the cloth sash bound around the tunic; Paul''s own.', 6),
  (11, 'τάδε λέγει', 'tade legei', 'G3592/G3004', '"Thus saith" — OT prophetic formula carried into NT prophecy.', 7),
  (13, 'συνθρύπτοντες', 'synthryptontes', 'G4919', 'Crushing together, breaking — NT hapax; breaking Paul''s heart.', 8),
  (13, 'ἑτοίμως ἔχω', 'hetoimōs echō', 'G2093/G2192', 'I am ready/prepared — Paul''s settled disposition toward bonds and death.', 9),
  (13, 'ὀνόματος', 'onomatos', 'G3686', 'Name — the cause and honour of the Lord Jesus.', 10),
  (14, 'τὸ θέλημα τοῦ Κυρίου', 'to thelēma tou Kyriou', 'G2307/G2962', 'The will of the Lord — Gethsemane''s prayer spread to the church.', 11),
  (16, 'ἀρχαίῳ μαθητῇ', 'archaiō mathētē', 'G744/G3101', 'An old (early) disciple — believer from the first generation.', 12),
  (18, 'Ἰάκωβον', 'Iakōbon', 'G2385', 'James — the Lord''s brother, leader of the Jerusalem church.', 13),
  (19, 'ἐξηγεῖτο', 'exēgeito', 'G1834', 'To expound, narrate in detail — root of "exegesis."', 14),
  (20, 'μυριάδες', 'myriades', 'G3461', 'Myriads, tens of thousands — the size of the Jerusalem church.', 15),
  (20, 'ζηλωταὶ τοῦ νόμου', 'zēlōtai tou nomou', 'G2207/G3551', 'Zealots of the law — Torah-observant Jewish Christians.', 16),
  (21, 'ἀποστασίαν', 'apostasian', 'G646', 'Apostasy, forsaking — the charge against Paul''s teaching.', 17),
  (23, 'εὐχὴν', 'euchēn', 'G2171', 'Vow — the Nazirite vow of Numbers 6.', 18),
  (24, 'ἁγνίσθητι', 'hagnisthēti', 'G48', 'Be purified — Levitical ritual purification.', 19),
  (24, 'δαπάνησον', 'dapanēson', 'G1159', 'Pay the expenses — fund the Nazirite offerings.', 20),
  (24, 'στοιχεῖς', 'stoicheis', 'G4748', 'Walk orderly, in line — conform to the pattern.', 21),
  (28, 'κεκοίνωκε', 'kekoinōke', 'G2840', 'Has polluted, made common — the charge of defiling the holy place.', 22),
  (29, 'Τρόφιμον', 'Trophimon', 'G5161', 'Trophimus — Ephesian Gentile delegate (20:4).', 23),
  (30, 'συνδρομὴ', 'syndromē', 'G4890', 'Running together, concourse — violent mob assembly.', 24),
  (31, 'χιλιάρχῳ', 'chiliarchō', 'G5506', 'Chiliarch, Roman military tribune — commander of a cohort.', 25),
  (31, 'σπείρης', 'speirēs', 'G4686', 'Cohort — ~600-1000 Roman soldiers garrisoned in Antonia.', 26),
  (33, 'ἁλύσεσι δυσί', 'halysesi dysi', 'G254/G1417', 'Two chains — exact fulfilment of Agabus''s sign (v.11).', 27),
  (34, 'παρεμβολήν', 'parembolēn', 'G3925', 'Camp, barracks — the Antonia Fortress garrison.', 28),
  (36, 'Αἶρε αὐτόν', 'Aire auton', 'G142', 'Away with him — the identical cry against Christ in John 19:15.', 29),
  (38, 'σικαρίων', 'sikariōn', 'G4607', 'Assassins, dagger-men — Zealot political murderers.', 30),
  (39, 'Ταρσεύς', 'Tarseus', 'G5018', 'Tarsian — of Tarsus, free city and university of Cilicia.', 31),
  (39, 'οὐκ ἀσήμου', 'ouk asēmou', 'G767', 'Of no mean (distinction) — litotes for illustrious.', 32),
  (40, 'κατέσεισε', 'kateseise', 'G2678', 'Motioned, beckoned downward — gesture for silence.', 33),
  (40, 'Ἑβραΐδι διαλέκτῳ', 'Hebraïdi dialektō', 'G1446/G1258', 'Hebrew dialect — Aramaic, the vernacular of Judaea.', 34)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 21 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

